---
import { useEffect } from 'astro/runtime';
---
<nav class="sticky top-0 bg-white dark:bg-gray-800 shadow-md p-4 flex justify-between items-center">
  <a href="/" class="text-xl font-bold text-gray-900 dark:text-gray-100">lukaspitrik.cz</a>
  <button id="theme-toggle" class="p-2 rounded bg-gray-200 dark:bg-gray-700">
    🌙
  </button>
</nav>

<script client:load>
  const btn = document.getElementById('theme-toggle');
  const darkClass = 'dark';
  const prefersDark = window.matchMedia('(prefers-color-scheme: dark)');
  const current = localStorage.getItem('theme');
  if (current) {
    document.documentElement.classList.toggle(darkClass, current === 'dark');
  } else if (prefersDark.matches) {
    document.documentElement.classList.add(darkClass);
    localStorage.setItem('theme', 'dark');
  }
  btn.addEventListener('click', () => {
    const isDark = document.documentElement.classList.toggle(darkClass);
    localStorage.setItem('theme', isDark ? 'dark' : 'light');
  });
</script>

