import { pa11y } from 'pa11y';
import fs from 'fs/promises';
import path from 'path';

const BASE_URL = 'http://localhost:4321';
const PAGES = [
  { name: 'homepage', path: '/' },
  { name: 'about', path: '/about' },
  { name: 'blog', path: '/blog' }
];

async function runAudit() {
  const results = [];

  for (const page of PAGES) {
    console.log(`\nAuditing: ${BASE_URL}${page.path}`);

    try {
      const result = await pa11y(`${BASE_URL}${page.path}`, {
        standard: 'WCAG2AA',
        runners: ['axe']
      });

      results.push({
        page: page.name,
        url: `${BASE_URL}${page.path}`,
        issues: result.issues
      });

      if (result.issues.length > 0) {
        console.log(`  ⚠ ${result.issues.length} issues found`);
      } else {
        console.log(`  ✓ No issues`);
      }
    } catch (error) {
      console.error(`  ✗ Error: ${error.message}`);
    }
  }

  // Generate report
  const reportPath = 'pa11y-report.json';
  await fs.writeFile(
    reportPath,
    JSON.stringify(results, null, 2)
  );
  console.log(`\nReport saved to: ${reportPath}`);

  // Exit with error if issues found
  const totalIssues = results.reduce((sum, r) => sum + r.issues.length, 0);
  if (totalIssues > 0) {
    console.error(`\n✗ Found ${totalIssues} total accessibility issues`);
    process.exit(1);
  }
}

runAudit();
```

