---
import '../styles/input.css';

interface LayoutProps {
  title?: string;
  description?: string;
  image?: string;
}

const { title = 'STAVEBNÍ PRÁCE Lukáš Pitřík | Teplice', description = 'Rodinná firma zaměřená na stavební práce v oblasti Severních Čech. Sádrokarton, obklady, beton, kompletní rekonstrukce.', image } = Astro.props as LayoutProps;
---

<!doctype html>
<html lang="cs">
  <head>
    <meta charset="UTF-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <meta name="description" content={description} />
    <meta property="og:title" content={title} />
    <meta property="og:description" content={description} />
    {image && <meta property="og:image" content={image} />}
    <title>{title}</title>
    <link rel="icon" type="image/svg+xml" href="/favicon.svg" />
  </head>
  <body class="bg-slate-50 dark:bg-slate-900 text-slate-800 dark:text-slate-100 transition-colors">
    <slot />
    <script>
      // Dark mode init
      const darkClass = 'dark';
      const prefersDark = window.matchMedia('(prefers-color-scheme: dark)');
      const current = localStorage.getItem('theme');
      if (current) {
        document.documentElement.classList.toggle(darkClass, current === 'dark');
      } else if (prefersDark.matches) {
        document.documentElement.classList.add(darkClass);
        localStorage.setItem('theme', 'dark');
      }
    </script>
  </body>
</html>

